// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	// evaluate this on load and on change
	// NOTE: This was in a UI Policy, but the policy was causing the form UI Actions to fail for portal.
	//       So, moved into onChnage and also running on load.
	if(g_form.getValue('category') +'' != ''){
		if (g_form.getControl('sub_category')){
			g_form.setDisplay('sub_category', true);
			g_form.setDisabled('sub_category', false);	
		}
	} else {
		if (g_form.getControl('sub_category')){
			g_form.setDisplay('sub_category', false);
			g_form.setDisabled('sub_category', true);	
		}
	}
}
